-- SOZZIAL NYC STARTER SPOTS
-- Adds 20 real NYC pizza spots so the public map is not empty.
-- Safe to rerun: it skips any spot with the same name already present.
-- Prices are public-menu prices where available, otherwise launch estimates to review from Admin.

insert into public.spots (name, address, lat, lng, slice_price, best_slice, quick_note, photo_url, status, created_at, updated_at)
select * from (values
  ('Joe''s Pizza - Carmine St', '7 Carmine St, New York, NY 10014', 40.730610, -74.002720, 2.75, 'Plain cheese slice', 'Classic Greenwich Village slice shop. Menu references list plain cheese slices at $2.75, but verify in-store before launch.', 'https://images.unsplash.com/photo-1565299624946-b28f40a0ae38?auto=format&fit=crop&w=1200&q=80', 'approved', now(), now()),
  ('Scarr''s Pizza', '35 Orchard St, New York, NY 10002', 40.715420, -73.991640, 4.50, 'Original slice', 'Official menu lists Original slice at $4.50 and Margherita at $5.50.', 'https://images.unsplash.com/photo-1548369937-47519962c11a?auto=format&fit=crop&w=1200&q=80', 'approved', now(), now()),
  ('L''Industrie Pizzeria - Williamsburg', '254 S 2nd St, Brooklyn, NY 11211', 40.711620, -73.957830, 4.50, 'Burrata slice', 'Williamsburg favorite. Whole pie prices are public; slice price should be verified on-site.', 'https://images.unsplash.com/photo-1594007654729-407eedc4be65?auto=format&fit=crop&w=1200&q=80', 'approved', now(), now()),
  ('L''Industrie Pizzeria - West Village', '104 Christopher St, New York, NY 10014', 40.733380, -74.005020, 4.50, 'Burrata slice', 'West Village location of L''Industrie. Use as a premium slice baseline; verify live menu price.', 'https://images.unsplash.com/photo-1601924582970-9238bcb495d9?auto=format&fit=crop&w=1200&q=80', 'approved', now(), now()),
  ('Prince Street Pizza', '27 Prince St, New York, NY 10012', 40.723090, -73.994530, 5.50, 'Spicy Spring square', 'Iconic Soho square slice. Launch estimate; verify current counter price.', 'https://images.unsplash.com/photo-1574071318508-1cdbab80d002?auto=format&fit=crop&w=1200&q=80', 'approved', now(), now()),
  ('John''s of Bleecker Street', '278 Bleecker St, New York, NY 10014', 40.731610, -74.003320, 5.00, 'Coal oven pie', 'Historic whole-pie spot, not a classic slice counter. Price is per-slice equivalent estimate.', 'https://images.unsplash.com/photo-1571997478779-2adcbbe9ab2f?auto=format&fit=crop&w=1200&q=80', 'approved', now(), now()),
  ('Bleecker Street Pizza', '69 7th Ave S, New York, NY 10014', 40.731990, -74.003100, 4.25, 'Nonna Maria slice', 'Village late-night slice stop. Launch estimate; verify current counter price.', 'https://images.unsplash.com/photo-1513104890138-7c749659a591?auto=format&fit=crop&w=1200&q=80', 'approved', now(), now()),
  ('Lucali', '575 Henry St, Brooklyn, NY 11231', 40.681800, -74.000240, 5.50, 'Plain pie', 'Destination whole-pie restaurant in Carroll Gardens. Price is per-slice equivalent estimate.', 'https://images.unsplash.com/photo-1620374645498-af6bd681a0bd?auto=format&fit=crop&w=1200&q=80', 'approved', now(), now()),
  ('Di Fara Pizza', '1424 Avenue J, Brooklyn, NY 11230', 40.625010, -73.961520, 5.00, 'Regular slice', 'Legendary Midwood pizzeria. Launch estimate; verify current slice price.', 'https://images.unsplash.com/photo-1593504049359-74330189a345?auto=format&fit=crop&w=1200&q=80', 'approved', now(), now()),
  ('Patsy''s Pizzeria - East Harlem', '2287 1st Ave, New York, NY 10035', 40.797110, -73.934150, 4.50, 'Coal oven pie', 'Classic coal-oven institution. Price is per-slice equivalent estimate.', 'https://images.unsplash.com/photo-1595708684082-a173bb3a06c5?auto=format&fit=crop&w=1200&q=80', 'approved', now(), now()),
  ('Artichoke Basille''s Pizza - East Village', '328 E 14th St, New York, NY 10003', 40.731150, -73.984480, 6.35, 'Margherita slice', 'Delivery menus show Margherita slice around $6.35 and Artichoke slice above $7; verify by location.', 'https://images.unsplash.com/photo-1588315029754-2dd089d39a1a?auto=format&fit=crop&w=1200&q=80', 'approved', now(), now()),
  ('Mama''s TOO! - Upper West Side', '2750 Broadway, New York, NY 10025', 40.800730, -73.967870, 5.00, 'House square slice', 'Upper West Side square-slice favorite. Launch estimate; verify current counter price.', 'https://images.unsplash.com/photo-1604917877934-07d8d248d396?auto=format&fit=crop&w=1200&q=80', 'approved', now(), now()),
  ('Best Pizza', '33 Havemeyer St, Brooklyn, NY 11211', 40.716010, -73.953900, 4.00, 'White slice', 'Williamsburg neighborhood staple. Launch estimate; verify current counter price.', 'https://images.unsplash.com/photo-1590947132387-155cc02f3212?auto=format&fit=crop&w=1200&q=80', 'approved', now(), now()),
  ('Paulie Gee''s Slice Shop', '110 Franklin St, Brooklyn, NY 11222', 40.729520, -73.957260, 4.50, 'Hellboy slice', 'Greenpoint slice shop from Paulie Gee''s. Launch estimate; verify current counter price.', 'https://images.unsplash.com/photo-1604382354936-07c5d9983bd3?auto=format&fit=crop&w=1200&q=80', 'approved', now(), now()),
  ('Roberta''s', '261 Moore St, Brooklyn, NY 11206', 40.704930, -73.933820, 5.50, 'Margherita pie', 'Bushwick wood-fired institution. Price is per-slice equivalent estimate.', 'https://images.unsplash.com/photo-1564936281291-294551497d81?auto=format&fit=crop&w=1200&q=80', 'approved', now(), now()),
  ('Juliana''s Pizza', '19 Old Fulton St, Brooklyn, NY 11201', 40.702750, -73.993430, 5.00, 'Margherita pie', 'DUMBO coal-oven pizza destination. Price is per-slice equivalent estimate.', 'https://images.unsplash.com/photo-1544982503-9f984c14501a?auto=format&fit=crop&w=1200&q=80', 'approved', now(), now()),
  ('Grimaldi''s Pizzeria', '1 Front St, Brooklyn, NY 11201', 40.702590, -73.993240, 5.00, 'Coal brick-oven pie', 'Famous DUMBO pizza stop. Price is per-slice equivalent estimate.', 'https://images.unsplash.com/photo-1628840042765-356cda07504e?auto=format&fit=crop&w=1200&q=80', 'approved', now(), now()),
  ('F&F Pizzeria', '459 Court St, Brooklyn, NY 11231', 40.677820, -73.998850, 4.50, 'Tomato slice', 'Carroll Gardens slice shop from the Franks team. Launch estimate; verify current price.', 'https://images.unsplash.com/photo-1593560708920-61dd98c46a4e?auto=format&fit=crop&w=1200&q=80', 'approved', now(), now()),
  ('Upside Pizza - Nolita', '51 Spring St, New York, NY 10012', 40.721770, -73.996230, 4.50, 'Sourdough slice', 'Modern NYC slice shop. Launch estimate; verify current counter price.', 'https://images.unsplash.com/photo-1600628421055-4d30de868b8f?auto=format&fit=crop&w=1200&q=80', 'approved', now(), now()),
  ('Sottocasa Pizzeria', '298 Atlantic Ave, Brooklyn, NY 11201', 40.688710, -73.989760, 5.00, 'Margherita pie', 'Cozy Boerum Hill Neapolitan spot. Price is per-slice equivalent estimate.', 'https://images.unsplash.com/photo-1613564834361-9436948817d1?auto=format&fit=crop&w=1200&q=80', 'approved', now(), now())
) as seed(name,address,lat,lng,slice_price,best_slice,quick_note,photo_url,status,created_at,updated_at)
where not exists (
  select 1 from public.spots s where lower(trim(s.name)) = lower(trim(seed.name))
);